/// Given an extract element instruction with constant index, return the shuffle
/// mask for a shuffle that does the same thing as the extract. Return nullptr
/// if we can't do this.
static Constant *getExtractMask(ExtractElementInst &Ext, InstCombinerImpl &IC) {
  auto *IdxC = dyn_cast<ConstantInt>(Ext.getIndexOperand());
  if (!IdxC)
    return nullptr;

  unsigned NumElts =
      cast<FixedVectorType>(Ext.getVectorOperandType())->getNumElements();
  unsigned Idx = IdxC->getZExtValue();

  // Try to canonicalize to a shuffle from operand 0. If we have an extract from
  // operand 1, we can swap the shuffle mask.
  Value *VecOp = Ext.getVectorOperand();
  unsigned OpNum = 0;
  if (auto *Shuf = dyn_cast<ShuffleVectorInst>(VecOp)) {
    if (Shuf->getOperand(0) == Ext.getVectorOperand()) {
      VecOp = Shuf->getOperand(0);
      OpNum = 0;
    } else if (Shuf->getOperand(1) == Ext.getVectorOperand()) {
      VecOp = Shuf->getOperand(1);
      OpNum = 1;
    }
  }

  SmallVector<int, 16> Mask;
  for (unsigned i = 0; i != NumElts; ++i)
    Mask.push_back(OpNum * NumElts + (i == Idx ? 0 : -1));
  return ConstantDataVector::get(Ext.getContext(), Mask);
}

/// Try to combine 2 shuffles into 1 shuffle by concatenating the shuffle masks.
static Value *foldShuffleOfShuffles(ShuffleVectorInst &Shuf,
                                    InstCombinerImpl &IC) {
  // We are going to try to combine this shuffle with its operand if it is also
  // a shuffle. However, we don't want to infinite loop, so we only consider
  // shuffles that are at the root of a chain of shuffles (no other shuffle uses
  // them).
  auto *ShufOp0 = dyn_cast<ShuffleVectorInst>(Shuf.getOperand(0));
  auto *ShufOp1 = dyn_cast<ShuffleVectorInst>(Shuf.getOperand(1));
  if (!ShufOp0 && !ShufOp1)
    return nullptr;

  // If both operands are shuffles, we can't easily combine them.
  if (ShufOp0 && ShufOp1)
    return nullptr;

  // The combined shuffle must not use more elements than the original 2
  // shuffles. This could happen if the original shuffles use different vector
  // sizes.
  unsigned NumElts =
      cast<FixedVectorType>(Shuf.getType())->getNumElements();
  auto *OpShuf = ShufOp0 ? ShufOp0 : ShufOp1;
  unsigned OpNum = ShufOp0 ? 0 : 1;
  unsigned OpElts =
      cast<FixedVectorType>(OpShuf->getType())->getNumElements();
  if (NumElts > 2 * OpElts)
    return nullptr;

  // We are going to create a new shuffle that concatenates the two original
  // shuffles' masks. Prepare the new mask.
  SmallVector<int, 16> NewMask;
  ArrayRef<int> ShufMask = Shuf.getShuffleMask();
  ArrayRef<int> OpShufMask = OpShuf->getShuffleMask();

  // The new shuffle will have the same number of elements as the original
  // shuffle.
  for (int MaskElt : ShufMask) {
    if (MaskElt == -1) {
      NewMask.push_back(-1);
    } else if (MaskElt < (int)OpElts) {
      // This element comes from the first operand of the original shuffle,
      // which is the shuffle instruction we're combining with.
      int OpMaskElt = OpShufMask[MaskElt];
      if (OpMaskElt == -1) {
        NewMask.push_back(-1);
      } else {
        NewMask.push_back(OpNum * OpElts + OpMaskElt);
      }
    } else {
      // This element comes from the second operand of the original shuffle.
      NewMask.push_back(MaskElt);
    }
  }

  // Create the new shuffle.
  Value *NewShuf = IC.Builder.CreateShuffleVector(
      OpShuf->getOperand(0), OpShuf->getOperand(1), NewMask);
  if (auto *NewShufInst = dyn_cast<Instruction>(NewShuf))
    IC.insertNewInstBefore(NewShufInst, Shuf);
  return NewShuf;
}

/// Try to combine a shuffle with an insert element instruction.
static Instruction *foldShuffleWithInsert(ShuffleVectorInst &Shuf,
