  // operand.
  Value *Op0 = Shuf.getOperand(0);
  Value *Op1 = Shuf.getOperand(1);
  auto *IE = dyn_cast<InsertElementInst>(Op0);
  if (!IE || !IE->hasOneUse())
    IE = dyn_cast<InsertElementInst>(Op1);
  if (!IE || !IE->hasOneUse())
    return nullptr;

  // The insert element must be inserting into a constant vector or undef.
  auto *VecC = dyn_cast<Constant>(IE->getOperand(0));
  if (!VecC || (!isa<ConstantVector>(VecC) && !isa<ConstantDataVector>(VecC) &&
                !isa<UndefValue>(VecC)))
    return nullptr;

  // Get the constant index of the insert.
  auto *IdxC = dyn_cast<ConstantInt>(IE->getIndexOperand());
  if (!IdxC)
    return nullptr;

  unsigned NumElts =
      cast<FixedVectorType>(Shuf.getType())->getNumElements();
  unsigned InsertIdx = IdxC->getZExtValue();

  // Check if the shuffle is only selecting the inserted element from the insert
  // instruction.
  ArrayRef<int> Mask = Shuf.getShuffleMask();
  bool OnlyUsesInsertedElement = true;
  for (int MaskElt : Mask) {
    if (MaskElt == -1)
      continue;
    unsigned OpNum = (unsigned)MaskElt / NumElts;
    unsigned OpElt = (unsigned)MaskElt % NumElts;
    if (OpNum == 0 && OpElt == InsertIdx) {
      // This is the inserted element.
    } else if (isa<UndefValue>(VecC)) {
      // The vector is undef, so any element is fine.
    } else if (auto *CV = dyn_cast<ConstantVector>(VecC)) {
