      if (CDV->getElementAsConstant(OpElt)->isNullValue()) {
        // The element is zero (common case).
      } else {
        OnlyUsesInsertedElement = false;
        break;
      }
    } else {
      OnlyUsesInsertedElement = false;
      break;
    }
  }

  if (!OnlyUsesInsertedElement)
    return nullptr;

  // Replace the shuffle with the inserted value.
  return IC.replaceInstUsesWith(Shuf, IE->getOperand(1));
}

/// Try to combine a shuffle with a binop.
static Instruction *foldShuffleWithBinop(ShuffleVectorInst &Shuf,
                                         InstCombinerImpl &IC) {
  // Look for a binop that is the sole user of the shuffle operand.
  Value *Op0 = Shuf.getOperand(0);
  Value *Op1 = Shuf.getOperand(1);
  auto *BO = dyn_cast<BinaryOperator>(Op0);
  if (!BO || !BO->hasOneUse())
    BO = dyn_cast<BinaryOperator>(Op1);
  if (!BO || !BO->hasOneUse())
    return nullptr;

  // The binop must be commutative and have constant operands.
  if (!BO->isCommutative())
    return nullptr;
  auto *C0 = dyn_cast<Constant>(BO->getOperand(0));
  auto *C1 = dyn_cast<Constant>(BO->getOperand(1));
  if (!C0 || !C1)
    return nullptr;

  // Check if the shuffle is only selecting elements from one operand of the
  // binop.
  unsigned NumElts =
      cast<FixedVectorType>(Shuf.getType())->getNumElements();
  ArrayRef<int> Mask = Shuf.getShuffleMask();
  bool OnlyUsesOp0 = true;
  bool OnlyUsesOp1 = true;
  for (int MaskElt : Mask) {
    if (MaskElt == -1)
      continue;
    unsigned OpNum = (unsigned)MaskElt / NumElts;
    if (OpNum == 0)
      OnlyUsesOp1 = false;
    else
      OnlyUsesOp0 = false;
  }

  if (!OnlyUsesOp0 && !OnlyUsesOp1)
    return nullptr;

  // Replace the shuffle with the constant operand.
  Constant *C = OnlyUsesOp0 ? C0 : C1;
  return IC.replaceInstUsesWith(Shuf, C);
