    SI = dyn_cast<SelectInst>(Op1);
  if (!SI || !SI->hasOneUse())
    return nullptr;

  // The select must have constant operands.
  auto *TV = dyn_cast<Constant>(SI->getTrueValue());
  auto *FV = dyn_cast<Constant>(SI->getFalseValue());
  if (!TV || !FV)
    return nullptr;

  // Check if the shuffle is only selecting elements from one operand of the
  // select.
  unsigned NumElts =
      cast<FixedVectorType>(Shuf.getType())->getNumElements();
  ArrayRef<int> Mask = Shuf.getShuffleMask();
  bool OnlyUsesTrue = true;
  bool OnlyUsesFalse = true;
  for (int MaskElt : Mask) {
    if (MaskElt == -1)
      continue;
