    else
      OnlyUsesTrue = false;
  }

  if (!OnlyUsesTrue && !OnlyUsesFalse)
    return nullptr;

  // Replace the shuffle with the constant operand.
  Constant *C = OnlyUsesTrue ? TV : FV;
  return IC.replaceInstUsesWith(Shuf, C);
}

