/// Try to combine a shuffle with a binop.
static Instruction *foldShuffleWithBinop(ShuffleVectorInst &Shuf,
                                         InstCombinerImpl &IC) {
  // Look for a binop that is the sole user of the shuffle operand.
  Value *Op0 = Shuf.getOperand(0);
  Value *Op1 = Shuf.getOperand(1);
  auto *BO = dyn_cast<BinaryOperator>(Op0);
  if (!BO || !BO->hasOneUse())
    BO = dyn_cast<BinaryOperator>(Op1);
  if (!BO || !BO->hasOneUse())
    return nullptr;

